const express = require('express');
const axios = require('axios');
const app = express();

const orders = [
  { id: 1, userId: 1, item: 'Book' },
  { id: 2, userId: 2, item: 'Pen' },
];

app.get('/orders', async (req, res) => {
  try {
    // Fetch users from User Service
    const userResponse = await axios.get('http://localhost:3001/users');
    const users = userResponse.data;

    // Combine order with user info
    const ordersWithUser = orders.map(order => {
      const user = users.find(u => u.id === order.userId);
      return { ...order, user };
    });

    res.json(ordersWithUser);
  } catch (error) {
    res.status(500).json({ error: 'Failed to fetch users' });
  }
});

const PORT = 3002;
app.listen(PORT, () => {
  console.log(`Order Service running on port ${PORT}`);
});

function validateType(value, type) {
  return typeof value === type;
}

console.log(validateType(25, 'number')); // true
console.log(validateType('hello', 'string')); // true
console.log(validateType(true, 'boolean')); // true
console.log(validateType({}, 'object')); // true
console.log(validateType(null, 'object')); // true (special case in JS)

function isRequired(value) {
  return value !== undefined && value !== null && value !== '';
}

console.log(isRequired('')); // false
console.log(isRequired(null)); // false
console.log(isRequired('Valid input')); // true

function validateNumberRange(num, min, max) {
  if (typeof num !== 'number') return false;
  return num >= min && num <= max;
}

console.log(validateNumberRange(10, 1, 100)); // true
console.log(validateNumberRange(0, 1, 100)); // false

function validateEmail(email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

console.log(validateEmail('user@example.com')); // true
console.log(validateEmail('invalid-email')); // false

function validateUser(user) {
  if (typeof user !== 'object' || user === null) return false;
  if (!isRequired(user.name) || typeof user.name !== 'string') return false;
  if (!validateNumberRange(user.age, 0, 120)) return false;
  if (!validateEmail(user.email)) return false;
  return true;
}

const user1 = { name: 'Alice', age: 30, email: 'alice@example.com' };
const user2 = { name: '', age: 150, email: 'bademail' };

console.log(validateUser(user1)); // true
console.log(validateUser(user2)); // false

function validateUserWithErrors(user) {
  if (typeof user !== 'object' || user === null) {
    return { valid: false, error: 'User data should be an object.' };
  }
  if (!isRequired(user.name) || typeof user.name !== 'string') {
    return { valid: false, error: 'Name is required and should be a string.' };
  }
  if (!validateNumberRange(user.age, 0, 120)) {
    return { valid: false, error: 'Age should be between 0 and 120.' };
  }
  if (!validateEmail(user.email)) {
    return { valid: false, error: 'Email is invalid.' };
  }
  return { valid: true };
}

const result = validateUserWithErrors({ name: '', age: 25, email: 'test@domain' });
if (!result.valid) {
  console.error('Validation error:', result.error);
}

function fibonacci(n: number): number {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2);
}

// Test the function
console.log('Fibonacci(10):', fibonacci(10));

const n = 35;
console.time('Native JS Fibonacci');
const result = fibonacci(n);
console.timeEnd('Native JS Fibonacci');
console.log(`Result: ${result}`);

async function loadWasmAndRun(n: number) {
  const response = await fetch('fibonacci.wasm');
  const buffer = await response.arrayBuffer();
  const wasmModule = await WebAssembly.instantiate(buffer);

  console.time('WebAssembly Fibonacci');
  const result = wasmModule.instance.exports.fibonacci(n);
  console.timeEnd('WebAssembly Fibonacci');
  console.log(`WASM Result: ${result}`);
}

loadWasmAndRun(35);

function divide(a, b) {
  try {
    if (b === 0) {
      throw new Error('Division by zero is not allowed.');
    }
    return a / b;
  } catch (error) {
    console.error(error.message);
    return null;
  }
}

console.log(divide(10, 2)); // 5
console.log(divide(10, 0)); // Logs error and returns null

function divideTS(a: number, b: number): number | null {
  try {
    if (b === 0) {
      throw new Error('Division by zero is not allowed.');
    }
    return a / b;
  } catch (error) {
    if (error instanceof Error) {
      console.error(error.message);
    }
    return null;
  }
}

console.log(divideTS(10, 2)); // 5
console.log(divideTS(10, 0)); // Logs error and returns null

type Result<T> = { success: true; value: T } | { success: false; error: string };

function safeDivide(a: number, b: number): Result<number> {
  if (b === 0) {
    return { success: false, error: 'Division by zero is not allowed.' };
  }
  return { success: true, value: a / b };
}

const result = safeDivide(10, 0);

if (result.success) {
  console.log('Result:', result.value);
} else {
  console.error('Error:', result.error);
}

